import{_ as e,l as t,s as n,t as r}from"./_plugin-vue_export-helper-CcuYJ4Jw.js";var i={class:`about-page`},a=r({__name:`About`,setup(r){return(r,a)=>(e(),n(`div`,i,[...a[0]||=[t(`<div class="title-box" data-v-ebff452d><h1 data-v-ebff452d>About Us</h1></div><div class="about-content" data-v-ebff452d><p data-v-ebff452d>Taian Honria Trading Co., Ltd. was established in 2013, building on our sourcing experience that began in 2011 through direct involvement in mining procurement projects.</p><p data-v-ebff452d>We specialize in underground mining and tunneling support materials, with a core focus on ground support solutions. Our product range includes anchor bolts, split sets, wire mesh, steel plates, rails, mine cars, and grinding media.</p><h3 data-v-ebff452d>What We Do</h3><p data-v-ebff452d>We work with selected manufacturing partners to supply products that meet practical underground application requirements. Our focus is not only on product delivery, but also on stable performance, consistent quality, and reliable supply across repeated orders.</p><h3 data-v-ebff452d>Quality Control</h3><p data-v-ebff452d>Quality is managed through a structured inspection process that includes:</p><ul data-v-ebff452d><li data-v-ebff452d>Raw material verification</li><li data-v-ebff452d>Production monitoring</li><li data-v-ebff452d>Pre-shipment inspection</li><li data-v-ebff452d>Batch consistency checks</li><li data-v-ebff452d>Inspection documentation for traceability</li></ul><p data-v-ebff452d>In addition, some of our manufacturing partners are certified under ISO management systems, and all product quality claims are supported by inspection records and related documentation.</p><h3 data-v-ebff452d>Our Technical Understanding</h3><p data-v-ebff452d>Underground mining conditions can vary significantly from site to site. Product performance may be affected by ground conditions, installation methods, corrosion exposure, and operational demands.</p><p data-v-ebff452d>With practical experience in mining supply, we understand the importance of matching the right support product to the right application. This helps our customers reduce risk and improve consistency underground.</p><h3 data-v-ebff452d>Our Role in the Supply Chain</h3><p data-v-ebff452d>Honria acts as a bridge between mine sites and manufacturing resources. We help customers balance quality, delivery stability, and cost while keeping supply practical and dependable.</p><p data-v-ebff452d>Rather than focusing only on standard product descriptions, we pay attention to real project needs and long-term supply reliability.</p><h3 data-v-ebff452d>Our Commitment</h3><p data-v-ebff452d>At Honria, we believe reliable supply means more than shipping products on time. It means ensuring the products delivered are suitable for underground use, supported by inspection, and consistent from order to order.</p><p data-v-ebff452d>If you are looking for a dependable partner for underground support materials, Honria is ready to support your project.</p></div>`,2)]]))}},[[`__scopeId`,`data-v-ebff452d`]]);export{a as default};